import React from 'react'
import Boots from '../../assets/boots.png'
import './cart.css'
import { Button } from '../../style/Styled'

const Cart = ({openModal}) => {

    const carts = [
        {
            id: 1,
            image: Boots,
            title: "Nuriddin"
        }
    ]

    return (
        <div className='carts'>
            {carts.map((cart) => (
                    <div className='cart' key={cart.id}>
                        <img src={cart.image} alt='boots' width='300'/>
                        <h1>{cart.title}</h1>
                         <Button onClick={openModal}>Open</Button>
                    </div>
            ))}
        </div>
    )
} 

export default Cart
